import { GoldRushClient } from "@covalenthq/client-sdk";

const client = new GoldRushClient(process.env.GOLDRUSH_API_KEY);

async function findYieldOpportunities(agentWallet) {
  const balances = await client.BalanceService.getTokenBalancesForWalletAddress(
    "eth-mainnet", agentWallet
  );
  // Find tokens with pending DeFi rewards (positive quote change)
  const opportunities = (balances.data?.items ?? []).filter(
    item => (item.quote_24h ?? 0) > 0
  );
  return { agentWallet, opportunities };
}
